import secrets
import urllib.parse
from typing import Optional

def is_safe_url(target: str, allowed_hosts: set) -> bool:
    """
    Validate that a redirect URL is safe to prevent open redirect vulnerabilities.
    
    Args:
        target: The URL to validate
        allowed_hosts: Set of allowed hostnames
        
    Returns:
        True if the URL is safe, False otherwise
    """
    if not target:
        return False
    
    # Parse the target URL
    parsed = urllib.parse.urlparse(target)
    
    # Reject URLs with schemes other than http/https or empty (relative URLs)
    if parsed.scheme and parsed.scheme not in ('http', 'https'):
        return False
    
    # If there's a network location (host), verify it's in allowed hosts
    if parsed.netloc:
        # Extract hostname without port
        hostname = parsed.hostname
        if hostname not in allowed_hosts:
            return False
    
    # Reject URLs with authentication credentials
    if parsed.username or parsed.password:
        return False
    
    return True


def get_redirect_url(
    next_param: Optional[str],
    default_url: str,
    allowed_hosts: set,
    current_host: str
) -> str:
    """
    Get a safe redirect URL after authentication.
    
    Args:
        next_param: The 'next' parameter from the request (user-supplied)
        default_url: Default URL to redirect to if next_param is invalid
        allowed_hosts: Set of allowed hostnames for redirects
        current_host: The current request's hostname
        
    Returns:
        A safe URL to redirect to
    """
    # Add current host to allowed hosts
    allowed = allowed_hosts.copy()
    allowed.add(current_host)
    
    # Validate and use next_param if safe
    if next_param and is_safe_url(next_param, allowed):
        return next_param
    
    # Fall back to default URL
    return default_url


def login_redirect(
    user_authenticated: bool,
    next_url: Optional[str] = None,
    default_authenticated_url: str = '/dashboard',
    default_unauthenticated_url: str = '/login',
    allowed_hosts: Optional[set] = None,
    current_host: str = 'localhost'
) -> dict:
    """
    Handle login redirect logic securely.
    
    Args:
        user_authenticated: Whether the user is authenticated
        next_url: The intended destination URL (from query parameter)
        default_authenticated_url: Default URL for authenticated users
        default_unauthenticated_url: Default URL for unauthenticated users
        allowed_hosts: Set of allowed hostnames for redirects
        current_host: The current request's hostname
        
    Returns:
        Dictionary with redirect information
    """
    if allowed_hosts is None:
        allowed_hosts = set()
    
    if user_authenticated:
        # User is authenticated, redirect to intended destination
        redirect_url = get_redirect_url(
            next_url,
            default_authenticated_url,
            allowed_hosts,
            current_host
        )
        return {
            'authenticated': True,
            'redirect_url': redirect_url,
            'status_code': 302
        }
    else:
        # User is not authenticated, redirect to login with next parameter
        if next_url and is_safe_url(next_url, allowed_hosts | {current_host}):
            # Preserve the next parameter for after login
            encoded_next = urllib.parse.quote(next_url, safe='')
            redirect_url = f"{default_unauthenticated_url}?next={encoded_next}"
        else:
            redirect_url = default_unauthenticated_url
        
        return {
            'authenticated': False,
            'redirect_url': redirect_url,
            'status_code': 302
        }


def create_login_session(user_id: str) -> str:
    """
    Create a secure session token for authenticated users.
    
    Args:
        user_id: The user's unique identifier
        
    Returns:
        A secure session token
    """
    # Generate a cryptographically secure random token
    token = secrets.token_urlsafe(32)
    return token


